proof fn phi_1_leads_to_unfold_closure_bridge(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>, i: nat)
    requires
        p.leads_to(q).satisfied_by(ex),
    ensures
        p.implies(eventually(q)).satisfied_by(ex.suffix(i)),
{
    leads_to_unfold::<int>(ex, p, q);
}

proof fn phi_2_implies_apply_closure_bridge(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        p.implies(q).satisfied_by(ex),
        p.satisfied_by(ex),
    ensures
        q.satisfied_by(ex),
{
    implies_apply::<int>(ex, p, q);
}

proof fn phi_3_always_propagate_forwards_closure_bridge(ex: Execution<int>, p: TempPred<int>, i: nat, j: nat)
    requires
        always(p).satisfied_by(ex),
    ensures
        p.satisfied_by(ex.suffix(i).suffix(j)),
{
    always_propagate_forwards::<int>(ex, p, i);
    always_propagate_forwards::<int>(ex.suffix(i), p, j);
}

proof fn phi_4_eventually_proved_by_witness_closure_bridge(ex: Execution<int>, p: TempPred<int>, witness_idx: nat)
    requires
        p.satisfied_by(ex.suffix(witness_idx)),
    ensures
        eventually(p).satisfied_by(ex),
{
    eventually_proved_by_witness::<int>(ex, p, witness_idx);
}

proof fn phi_5_execution_equality_intensional_bridge(ex1: Execution<int>, ex2: Execution<int>)
    requires
        forall |i: nat| #[trigger] (ex1.nat_to_state)(i) == (ex2.nat_to_state)(i),
    ensures
        ex1 == ex2,
{
    execution_equality::<int>(ex1, ex2);
}
